# Exercício 5 - Monitor de Tráfego de Rede (Download e Upload)\n\n# importo as bibliotecas necessárias\nimport psutil\nimport time\nimport os\n\n# limpo a tela\nos.system(\"cls\")\n\nprint(\"=\"*60)\nprint(\"       MONITOR DE TRÁFEGO DE REDE\")\nprint(\"=\"*60)\nprint(\"Medindo... Pressione Ctrl+C para interromper\\n\")\n\n# variável para rastrear se é a primeira leitura\nprimeira_leitura = True\n\n# variáveis para armazenar a medição anterior\nbytes_recv_anterior = 0\nbytes_sent_anterior = 0\n\ntry:\n    while True:\n        # psutil.net_io_counters() retorna informações de rede\n        # retorna um objeto com: bytes_sent, bytes_recv, packets_sent, packets_recv, etc\n        stats_rede = psutil.net_io_counters()\n\n        # extraio os bytes enviados e recebidos até agora (total acumulado)\n        bytes_recv_total = stats_rede.bytes_recv  # total recebido desde o boot\n        bytes_sent_total = stats_rede.bytes_sent  # total enviado desde o boot\n\n        # se não é a primeira leitura, calculo a diferença (delta)\n        if not primeira_leitura:\n            # delta é a diferença entre a leitura atual e a anterior\n            # isso representa quanto foi enviado/recebido neste intervalo\n            bytes_recv_delta = bytes_recv_total - bytes_recv_anterior\n            bytes_sent_delta = bytes_sent_total - bytes_sent_anterior\n\n            # converto para KB (divido por 1024)\n            # como o intervalo é 1 segundo, isso já é KB/s\n            kb_s_recv = bytes_recv_delta / 1024\n            kb_s_sent = bytes_sent_delta / 1024\n\n            # limpo a tela\n            os.system(\"cls\")\n\n            # exibo as informações\n            print(\"\\n\" + \"=\"*60)\n            print(\"       MONITOR DE TRÁFEGO DE REDE\")\n            print(\"=\"*60)\n            print(f\"Download (recebimento): {kb_s_recv:.2f} KB/s\")\n            print(f\"Upload (envio):        {kb_s_sent:.2f} KB/s\")\n            print(\"=\"*60)\n            print(\"Atualizando a cada 1 segundo...\")\n            print(\"Pressione Ctrl+C para interromper\")\n\n        else:\n            # na primeira leitura, apenas inicializo e exibo mensagem\n            print(\"Coletando primeira amostra...\")\n            primeira_leitura = False\n\n        # guardo os valores atuais para a próxima iteração\n        bytes_recv_anterior = bytes_recv_total\n        bytes_sent_anterior = bytes_sent_total\n\n        # aguardo 1 segundo antes da próxima medição\n        time.sleep(1)\n\nexcept KeyboardInterrupt:\n    # se o usuário pressionar Ctrl+C, encerro gracefully\n    print(\"\\n\\nPrograma interrompido pelo usuário.\")\n\n# Anotações:\n# - psutil.net_io_counters() retorna estatísticas de rede ACUMULADAS\n#   * bytes_sent: total de bytes enviados desde o boot do sistema\n#   * bytes_recv: total de bytes recebidos desde o boot do sistema\n#   * packets_sent: total de pacotes enviados\n#   * packets_recv: total de pacotes recebidos\n#   * errin, errout, dropin, dropout: erros de rede (não usamos aqui)\n# - para calcular taxa por segundo, preciso usar DELTA (diferença)\n#   * delta = valor_atual - valor_anterior\n#   * assim descubro quanto foi transferido entre as duas medições\n# - intervalo de 1 segundo: se em 1 segundo recebeu X bytes, então é X bytes/s\n# - conversão:\n#   * bytes → KB: divide por 1024\n#   * bytes → MB: divide por 1024^2\n#   * bytes → GB: divide por 1024^3\n# - primeira_leitura é uma flag para não tentar calcular delta na primeira vez\n#   (não há dado anterior para comparar)\n# - try/except KeyboardInterrupt captura Ctrl+C do usuário\n